parameters.jsCode:
// Der Error Trigger liefert den Kontext des fehlgeschlagenen Workflow-Laufs.
// Wir ziehen die wichtigsten Felder defensiv heraus (Struktur variiert je
// nach Fehlerquelle) und bauen daraus ein flaches Fehler-Dokument.
const t = $input.first().json;
const execution = t.execution ?? {};
const workflow = t.workflow ?? {};
const err = execution.error ?? {};

const message = err.message ?? 'Unbekannter Fehler';
const failedNode = err.node?.name ?? execution.lastNodeExecuted ?? 'unbekannt';
const workflowName = workflow.name ?? 'unbekannt';
const workflowId = workflow.id ?? 'unbekannt';
const executionId = String(execution.id ?? 'n/a');
const executionUrl = execution.url ?? '';
const timestamp = new Date().toISOString();

// Eigene Doc-ID je Fehler (Zeitstempel + Execution-ID), Firestore-tauglich gemacht.
const docId = `${timestamp.replace(/[:.]/g, '-')}_${executionId}`;

return [{ json: { docId, workflowName, workflowId, failedNode, message, executionId, executionUrl, timestamp } }];

parameters.jsonBody:
={{ JSON.stringify({
  writes: [{
    update: {
      name: "projects/code-a-cuisine-9c87f/databases/(default)/documents/errors/" + $json.docId,
      fields: {
        workflowName: { stringValue: $json.workflowName },
        workflowId:   { stringValue: $json.workflowId },
        failedNode:   { stringValue: $json.failedNode },
        message:      { stringValue: $json.message },
        executionId:  { stringValue: $json.executionId },
        executionUrl: { stringValue: $json.executionUrl },
        timestamp:    { timestampValue: $json.timestamp }
      }
    }
  }]
}) }}
